class FlippinCard extends HTMLElement {
	constructor() {
		super();
		this.attachShadow({ mode: "open" });
		this.shadowRoot.innerHTML = `
            <style>
                :host {
                    // display: block;
                    // width: 300px;
                    // height: 400px;
                    perspective: 1000px;
                    // margin: 20px auto;
                }
                .card {
                    width: 100%;
                    height: 100%;
                    position: relative;
                    transform-style: preserve-3d;
                    transition: transform 0.6s ease;
                }
                .card.is_flipped {
                    transform: rotateY(180deg);
                }
                ::slotted([slot="front"]), ::slotted([slot="back"]) {
                    position: absolute;
                    width: 100%;
                    height: 100%;
                    backface-visibility: hidden;
                    // border-radius: 15px;
                    // display: flex;
                    // flex-direction: column;
                    // align-items: center;
                    // justify-content: center;
                    // font-family: sans-serif;
                }
                ::slotted([slot="back"]) {
                    transform: rotateY(180deg);
                }
            </style>
            <div class="card" id="card_wrapper">
                <slot name="front"></slot>
                <slot name="back"></slot>
            </div>
        `;
	}
	flip() {
		const card = this.shadowRoot.getElementById("card_wrapper");
		card.classList.toggle("is_flipped");
	}
}
customElements.define("flippin-card", FlippinCard);
